-- 06-evm-calculations.sql
-- 21 monthly EVM snapshots covering the project life from August 2024
-- (mobilisation) through April 2026 (data date).  Curve starts near zero
-- (mobilisation only), ramps up through 2025 as earthwork + sub-base + bridge
-- substructure execute, then continues into bituminous works in 2026.
-- The final row (data_date 2026-04-30) drives the Status tiles:
--   BAC = ₹452.5 Cr   PV = ₹360 Cr   EV = ₹339.4 Cr   AC = ₹358.2 Cr
--   CPI = 0.948       SPI = 0.943    EAC = ₹477.38 Cr  VAC = -₹24.88 Cr
--   TCPI ≈ 1.04       Performance % complete = 75.01%
-- All amounts in rupees.  BAC = 4,525,000,000.

INSERT INTO evm.evm_calculations (
    id, created_at, updated_at, version,
    project_id, data_date,
    budget_at_completion, planned_value, earned_value, actual_cost,
    cost_variance, schedule_variance,
    cost_performance_index, schedule_performance_index,
    estimate_at_completion, estimate_to_complete, variance_at_completion,
    to_complete_performance_index,
    evm_technique, etc_method, performance_percent_complete
)
SELECT
    gen_random_uuid(), CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, 0,
    p.id, m.data_date,
    m.bac, m.pv, m.ev, m.ac,
    m.cv, m.sv,
    m.cpi, m.spi,
    m.eac, m.etc, m.vac,
    m.tcpi,
    'ACTIVITY_PERCENT_COMPLETE', 'CPI_BASED', m.pct_complete
FROM (VALUES
    -- Aug 2024: mobilisation only — minimal PV / no EV booked yet
    (DATE '2024-08-31', 4525000000.00,   10000000.00,         0.00,         0.00,         0.00,  -10000000.00, 1.000, 0.000, 4525000000.00, 4525000000.00,         0.00, 1.000,  0.00),
    (DATE '2024-09-30', 4525000000.00,   40000000.00,   30000000.00,   35000000.00,  -5000000.00,  -10000000.00, 0.857, 0.750, 4525000000.00, 4490000000.00,         0.00, 1.001,  0.66),
    (DATE '2024-10-31', 4525000000.00,   80000000.00,   65000000.00,   75000000.00, -10000000.00,  -15000000.00, 0.867, 0.813, 4525000000.00, 4450000000.00,         0.00, 1.002,  1.44),
    (DATE '2024-11-30', 4525000000.00,  140000000.00,  125000000.00,  140000000.00, -15000000.00,  -15000000.00, 0.893, 0.893, 4525000000.00, 4385000000.00,         0.00, 1.003,  2.76),
    (DATE '2024-12-31', 4525000000.00,  220000000.00,  200000000.00,  225000000.00, -25000000.00,  -20000000.00, 0.889, 0.909, 4525000000.00, 4300000000.00,         0.00, 1.006,  4.42),
    (DATE '2025-01-31', 4525000000.00,  320000000.00,  295000000.00,  320000000.00, -25000000.00,  -25000000.00, 0.922, 0.922, 4525000000.00, 4205000000.00,         0.00, 1.006,  6.52),
    (DATE '2025-02-28', 4525000000.00,  440000000.00,  410000000.00,  440000000.00, -30000000.00,  -30000000.00, 0.932, 0.932, 4524000000.00, 4084000000.00,    1000000.00, 1.007,  9.06),
    (DATE '2025-03-31', 4525000000.00,  580000000.00,  540000000.00,  575000000.00, -35000000.00,  -40000000.00, 0.939, 0.931, 4818000000.00, 4243000000.00, -293000000.00, 1.011, 11.93),
    (DATE '2025-04-30', 4525000000.00,  750000000.00,  700000000.00,  740000000.00, -40000000.00,  -50000000.00, 0.946, 0.933, 4783000000.00, 4043000000.00, -258000000.00, 1.014, 15.47),
    (DATE '2025-05-31', 4525000000.00,  940000000.00,  880000000.00,  925000000.00, -45000000.00,  -60000000.00, 0.951, 0.936, 4756000000.00, 3831000000.00, -231000000.00, 1.017, 19.45),
    (DATE '2025-06-30', 4525000000.00, 1140000000.00, 1075000000.00, 1130000000.00, -55000000.00,  -65000000.00, 0.951, 0.943, 4756000000.00, 3626000000.00, -231000000.00, 1.018, 23.76),
    (DATE '2025-07-31', 4525000000.00, 1340000000.00, 1265000000.00, 1330000000.00, -65000000.00,  -75000000.00, 0.951, 0.944, 4757000000.00, 3427000000.00, -232000000.00, 1.020, 27.96),
    (DATE '2025-08-31', 4525000000.00, 1540000000.00, 1450000000.00, 1530000000.00, -80000000.00,  -90000000.00, 0.948, 0.942, 4774000000.00, 3244000000.00, -249000000.00, 1.022, 32.04),
    (DATE '2025-09-30', 4525000000.00, 1740000000.00, 1635000000.00, 1730000000.00, -95000000.00, -105000000.00, 0.945, 0.940, 4788000000.00, 3058000000.00, -263000000.00, 1.025, 36.13),
    (DATE '2025-10-31', 4525000000.00, 1950000000.00, 1830000000.00, 1940000000.00,-110000000.00, -120000000.00, 0.943, 0.938, 4797000000.00, 2857000000.00, -272000000.00, 1.027, 40.44),
    (DATE '2025-11-30', 4525000000.00, 2160000000.00, 2025000000.00, 2150000000.00,-125000000.00, -135000000.00, 0.942, 0.938, 4804000000.00, 2654000000.00, -279000000.00, 1.030, 44.75),
    (DATE '2025-12-31', 4525000000.00, 2380000000.00, 2225000000.00, 2360000000.00,-135000000.00, -155000000.00, 0.943, 0.935, 4799000000.00, 2439000000.00, -274000000.00, 1.032, 49.17),
    (DATE '2026-01-31', 4525000000.00, 2640000000.00, 2470000000.00, 2620000000.00,-150000000.00, -170000000.00, 0.943, 0.936, 4800000000.00, 2180000000.00, -275000000.00, 1.034, 54.59),
    (DATE '2026-02-28', 4525000000.00, 2920000000.00, 2740000000.00, 2900000000.00,-160000000.00, -180000000.00, 0.945, 0.938, 4790000000.00, 1890000000.00, -265000000.00, 1.034, 60.55),
    (DATE '2026-03-31', 4525000000.00, 3240000000.00, 3050000000.00, 3220000000.00,-170000000.00, -190000000.00, 0.947, 0.941, 4779000000.00, 1559000000.00, -254000000.00, 1.037, 67.40),
    -- Data date — drives the Status tiles
    (DATE '2026-04-30', 4525000000.00, 3600000000.00, 3394000000.00, 3582000000.00,-188000000.00, -206000000.00, 0.948, 0.943, 4773800000.00, 1191800000.00, -248800000.00, 1.040, 75.01)
) AS m(data_date, bac, pv, ev, ac, cv, sv, cpi, spi, eac, etc, vac, tcpi, pct_complete)
CROSS JOIN (SELECT id FROM project.projects WHERE code = 'OWD/SH10/OD/2025/001') AS p;
